namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN = 2048;
static constexpr uint32_t HARD_CAP = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k00253CustomTilingData tiling;

    const gert::StorageShape *x_shape = context->GetInputShape(0);
    const gert::StorageShape *w_shape = context->GetInputShape(1);

    tiling.set_N(static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0)));
    tiling.set_inC(static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1)));
    tiling.set_iH(static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2)));
    tiling.set_iW(static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3)));

    tiling.set_outC(static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0)));
    tiling.set_convK(static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(2)));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    uint32_t convS = static_cast<uint32_t>(attrs->GetAttrPointer<int>(0)[0]);
    tiling.set_poolS(static_cast<uint32_t>(attrs->GetAttrPointer<int>(2)[0]));

    uint32_t conv_oH = (tiling.get_iH() - tiling.get_convK()) / convS + 1;
    uint32_t conv_oW = (tiling.get_iW() - tiling.get_convK()) / convS + 1;
    tiling.set_oH(conv_oH / tiling.get_poolS());
    tiling.set_oW(conv_oW / tiling.get_poolS());

    uint32_t totalElems = tiling.get_N() * tiling.get_outC() * tiling.get_oH() * tiling.get_oW();

    uint32_t maxTile = UB_BUDGET_BYTES / 4;
    maxTile = AlignDown(maxTile, ALIGN);
    if (maxTile < ALIGN) maxTile = ALIGN;
    if (maxTile > HARD_CAP) maxTile = AlignDown(HARD_CAP, ALIGN);

    uint32_t tileLen = (totalElems < maxTile) ? totalElems : maxTile;
    tiling.set_tileLen(tileLen);

    uint32_t numTiles = CeilDiv(totalElems, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);
    tiling.set_blockDim(blockDim);
    tiling.set_totalElements(totalElems);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
